ALTER TABLE main.bi_db.gold_sql_dp_prod_we_exw_dbo_exw_financereportsbalancesnew SET TBLPROPERTIES (
    'comment' = 'EXW_FinanceReportsBalancesNew is the central daily balance snapshot used by the eToro Wallet finance team to track crypto holdings across all active Wallet users. With 1.62 billion rows, it stores one record per GCID × WalletID × CryptoID × date, covering 689,733 distinct users across 173 cryptocurrency types as of the latest snapshot (2026-04-11). The table is driven by WalletBalancesReportDB''s daily reconciliation engine, which cross-checks wallet balances across three systems: the blockchain ledger (TotalReceive - TotalSend), eToro''s internal computed ledger (ComputedAmount), and third-party providers BitGo (ProviderValue) and Blox (WalletTrackerValue). The SP applies a priority rule to select the "best available" balance: if no discrepancy was detected (LevelId IS NULL), BloxBalance is used; if a discrepancy was classified, the BitGoValue or BloxValue is preferred based on LevelId. The result is stored in Balance, and multiplied by the daily average crypto price (EXW_PriceDaily.AvgPrice) to produce Bal...'
);

ALTER TABLE main.bi_db.gold_sql_dp_prod_we_exw_dbo_exw_financereportsbalancesnew SET TAGS (
    'domain' = 'general',
